import { Express, Request, Response } from 'express';
import { eq, and } from 'drizzle-orm';
import { db } from '../db';
import { users } from '@shared/schema';
import {
  KoveoMcpOAuthProvider,
  MCP_SUPPORTED_ROLES,
  type McpRole,
} from './oauth-provider';

const COPY = {
  title: {
    en: 'Authorize MCP access',
    fr: "Autoriser l'accès MCP",
  },
  intro: {
    en: 'wants to connect to your Koveo Gestion data through the Model Context Protocol.',
    fr: 'souhaite se connecter à vos données Koveo Gestion via le Model Context Protocol.',
  },
  roleLabel: {
    en: 'Connect as',
    fr: 'Se connecter en tant que',
  },
  roleHelp: {
    en: 'Tools called by the connector will run with the permissions of this role.',
    fr: 'Les outils appelés par le connecteur s\u2019exécuteront avec les permissions de ce rôle.',
  },
  approve: { en: 'Approve', fr: 'Approuver' },
  deny: { en: 'Deny', fr: 'Refuser' },
  loginRequired: {
    en: 'Please sign in first, then return to this page to approve the request.',
    fr: 'Veuillez vous connecter, puis revenez à cette page pour approuver la demande.',
  },
  signIn: { en: 'Sign in', fr: 'Se connecter' },
  invalidFlow: {
    en: 'This authorization request is invalid or has expired.',
    fr: 'Cette demande d\u2019autorisation est invalide ou a expiré.',
  },
  scopesLabel: { en: 'Requested access', fr: 'Accès demandé' },
  signedInAs: { en: 'Signed in as', fr: 'Connecté en tant que' },
};

function pickLang(req: Request): 'en' | 'fr' {
  const q = (req.query.lang as string | undefined)?.toLowerCase();
  if (q === 'fr' || q === 'en') return q;
  const al = req.headers['accept-language'] ?? '';
  return /fr/i.test(al) ? 'fr' : 'en';
}

function escapeHtml(s: string): string {
  return s.replace(/[&<>"']/g, (c) =>
    c === '&'
      ? '&amp;'
      : c === '<'
      ? '&lt;'
      : c === '>'
      ? '&gt;'
      : c === '"'
      ? '&quot;'
      : '&#39;',
  );
}

function shellHtml(lang: 'en' | 'fr', body: string): string {
  return `<!doctype html>
<html lang="${lang}">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>Koveo Gestion \u2014 MCP</title>
<style>
  :root { color-scheme: light dark; }
  body { font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif; max-width: 520px; margin: 6vh auto; padding: 24px; line-height: 1.5; }
  h1 { font-size: 1.4rem; margin: 0 0 12px; }
  .card { border: 1px solid #d4d4d8; border-radius: 12px; padding: 24px; box-shadow: 0 1px 2px rgba(0,0,0,.04); }
  .muted { color: #6b7280; font-size: .9rem; }
  .row { margin: 16px 0; }
  label { display: block; font-weight: 600; margin-bottom: 6px; }
  select, button { font: inherit; padding: 8px 12px; border-radius: 8px; border: 1px solid #d4d4d8; }
  select { width: 100%; }
  .actions { display: flex; gap: 12px; justify-content: flex-end; margin-top: 24px; }
  button.primary { background: #1d4ed8; color: white; border-color: #1d4ed8; cursor: pointer; }
  button.secondary { background: white; color: #111; cursor: pointer; }
  .lang { float: right; font-size: .85rem; }
  .lang a { color: #6b7280; text-decoration: none; margin-left: 8px; }
  .scopes { background: #f4f4f5; border-radius: 8px; padding: 8px 12px; font-family: ui-monospace, monospace; font-size: .85rem; }
</style>
</head>
<body>
  <div class="card">
    ${body}
  </div>
</body>
</html>`;
}

export function registerOAuthConsentRoutes(
  app: Express,
  provider: KoveoMcpOAuthProvider,
) {
  app.get('/oauth/consent', async (req: Request, res: Response) => {
    const lang = pickLang(req);
    const flow = (req.query.flow as string | undefined) ?? '';
    const row = await provider.getPendingFlow(flow);

    if (!row || row.status !== 'pending' || row.expiresAt.getTime() < Date.now()) {
      res
        .status(400)
        .type('html')
        .send(
          shellHtml(
            lang,
            `<h1>${COPY.title[lang]}</h1><p>${COPY.invalidFlow[lang]}</p>`,
          ),
        );
      return;
    }

    const userId = req.session?.userId;
    if (!userId) {
      const next = encodeURIComponent(`/oauth/consent?flow=${encodeURIComponent(flow)}&lang=${lang}`);
      const otherLang = lang === 'en' ? 'fr' : 'en';
      const langLink = `<div class="lang"><a href="?flow=${encodeURIComponent(flow)}&lang=${otherLang}">${otherLang.toUpperCase()}</a></div>`;
      res
        .status(200)
        .type('html')
        .send(
          shellHtml(
            lang,
            `${langLink}
<h1>${COPY.title[lang]}</h1>
<p>${COPY.loginRequired[lang]}</p>
<div class="actions">
  <a class="primary" href="/auth/login?next=${next}" style="text-decoration:none;display:inline-block;background:#1d4ed8;color:white;padding:8px 16px;border-radius:8px">${COPY.signIn[lang]}</a>
</div>`,
          ),
        );
      return;
    }

    const userRows = await db.select().from(users).where(eq(users.id, userId)).limit(1);
    const user = userRows[0];
    const userEmail = user?.email ?? '';
    const userRole = (user?.role as McpRole | undefined) ?? 'tenant';
    const allowedRoles = MCP_SUPPORTED_ROLES.filter((r) => {
      if (userRole === 'admin') return true;
      if (userRole === 'manager') return r !== 'admin';
      return r === 'tenant';
    });

    const clientInfo = await provider.clientsStore.getClient(row.clientId);
    const clientName = clientInfo?.client_name ?? row.clientId;
    const scopes = (row.scopes && row.scopes.length > 0
      ? row.scopes
      : ['mcp']
    ).join(' ');

    const otherLang = lang === 'en' ? 'fr' : 'en';
    const langLink = `<div class="lang"><a href="?flow=${encodeURIComponent(flow)}&lang=${otherLang}">${otherLang.toUpperCase()}</a></div>`;

    const roleOptions = allowedRoles
      .map(
        (r) =>
          `<option value="${r}"${r === userRole ? ' selected' : ''}>${r}</option>`,
      )
      .join('');

    res
      .type('html')
      .send(
        shellHtml(
          lang,
          `${langLink}
<h1>${COPY.title[lang]}</h1>
<p><strong>${escapeHtml(clientName)}</strong> ${COPY.intro[lang]}</p>
<p class="muted">${COPY.signedInAs[lang]}: ${escapeHtml(userEmail)}</p>
<form method="POST" action="/oauth/consent">
  <input type="hidden" name="flow" value="${escapeHtml(flow)}" />
  <input type="hidden" name="lang" value="${lang}" />
  <div class="row">
    <label>${COPY.scopesLabel[lang]}</label>
    <div class="scopes">${escapeHtml(scopes)}</div>
  </div>
  <div class="row">
    <label for="role">${COPY.roleLabel[lang]}</label>
    <select name="role" id="role">${roleOptions}</select>
    <p class="muted">${COPY.roleHelp[lang]}</p>
  </div>
  <div class="actions">
    <button type="submit" name="decision" value="deny" class="secondary">${COPY.deny[lang]}</button>
    <button type="submit" name="decision" value="approve" class="primary">${COPY.approve[lang]}</button>
  </div>
</form>`,
        ),
      );
  });

  app.post('/oauth/consent', async (req: Request, res: Response) => {
    const lang = pickLang(req);
    const flow = (req.body?.flow as string | undefined) ?? '';
    const decision = (req.body?.decision as string | undefined) ?? 'deny';
    const role = (req.body?.role as string | undefined) ?? 'tenant';

    const userId = req.session?.userId;
    if (!userId) {
      res.status(401).type('html').send(shellHtml(lang, `<h1>${COPY.title[lang]}</h1><p>${COPY.loginRequired[lang]}</p>`));
      return;
    }

    const row = await provider.getPendingFlow(flow);
    if (!row || row.status !== 'pending' || row.expiresAt.getTime() < Date.now()) {
      res.status(400).type('html').send(shellHtml(lang, `<h1>${COPY.title[lang]}</h1><p>${COPY.invalidFlow[lang]}</p>`));
      return;
    }

    if (decision !== 'approve') {
      const denied = await provider.denyAuthorization(flow);
      if (!denied) {
        res.status(400).type('html').send(shellHtml(lang, `<h1>${COPY.title[lang]}</h1><p>${COPY.invalidFlow[lang]}</p>`));
        return;
      }
      const url = new URL(denied.redirectUri);
      url.searchParams.set('error', 'access_denied');
      if (denied.state) url.searchParams.set('state', denied.state);
      res.redirect(url.toString());
      return;
    }

    const userRows = await db
      .select()
      .from(users)
      .where(and(eq(users.id, userId)))
      .limit(1);
    const user = userRows[0];
    if (!user) {
      res.status(401).type('html').send(shellHtml(lang, `<h1>${COPY.title[lang]}</h1><p>${COPY.loginRequired[lang]}</p>`));
      return;
    }

    const userRole = user.role as McpRole;
    const requested = MCP_SUPPORTED_ROLES.includes(role as McpRole)
      ? (role as McpRole)
      : 'tenant';
    const effective: McpRole = (() => {
      if (userRole === 'admin') return requested;
      if (userRole === 'manager') return requested === 'admin' ? 'manager' : requested;
      return 'tenant';
    })();

    const finalized = await provider.finalizeAuthorization(flow, user.id, effective);
    const url = new URL(finalized.redirectUri);
    url.searchParams.set('code', finalized.code);
    if (finalized.state) url.searchParams.set('state', finalized.state);
    res.redirect(url.toString());
  });
}
